 *
 * @return query
 */
public query function getPublishedCategories() {
  return queryExecute(
    'SELECT id, name, slug FROM categories WHERE isPublished = 1 ORDER BY sortOrder',
    {},
    { datasource: variables.datasource, cachedWithin: createTimespan(0, 1, 0, 0) }
