/**
 * Returns active users; cached by region for selective clearing.
 *
 * @return query
 */
public query function getActiveUsers() {
  return queryExecute(
    'SELECT id, email, displayName FROM users WHERE isActive = 1',
    {},
    {
      datasource: variables.datasource,
      cachedWithin: createTimespan(0, 0, 30, 0),
      cacheId: 'active_users',
      cacheRegion: 'users'
    }
  );
}

/**
 * Updates a user record and invalidates the users cache region.
 *
 * @userId numeric        User identifier.
 * @userData struct       Fields to update.
 * @return void
 */
public void function updateUser(required numeric userId, required struct userData) {
  variables.userRepository.update(arguments.userId, arguments.userData);
  cacheRemove('active_users', false, 'users');
}

/**
 * Returns resolved permissions; computed once and cached for the request.
 *
 * @userId numeric   User identifier.
 * @return array
 */
public array function getResolvedPermissions(required numeric userId) {
  var cacheKey = 'permissions_' & arguments.userId;
  if (!structKeyExists(variables, cacheKey)) {
    variables[cacheKey] = variables.permissionService.resolve(arguments.userId);
  }
  return variables[cacheKey];
}

/**
 * Returns configuration values; cached in production only.
 *
 * @return query
 */
public query function getConfigValues() {
  var isDev = structKeyExists(application, 'isDevelopment') && application.isDevelopment;
  var opts = { datasource: variables.datasource };
  if (!isDev) {
    opts.cachedWithin = createTimespan(0, 4, 0, 0);
  }
  return queryExecute('SELECT configKey, configValue FROM app_config', {}, opts);
}

/**
 * Initializes the reference data cache thread-safely.
 *
 * @return void
 */
public void function warmReferenceCache() {
  if (!structKeyExists(application, 'referenceData')) {
    lock name='referenceDataLock' type='exclusive' timeout=10 {
      if (!structKeyExists(application, 'referenceData')) {
        application.referenceData = variables.referenceRepository.loadAll();
      }
    }
  }
}

