/**
 * Returns user profile using the cache-aside pattern.
 *
 * @userId numeric   User identifier.
 * @return struct
 */
public struct function getCachedProfile(required numeric userId) {
  var cacheKey = 'profile_' & arguments.userId;
  var cached = cacheGet(cacheKey);
  if (!isNull(cached)) {
    return cached;
  }
  var profile = variables.userRepository.getProfile(arguments.userId);
  cachePut(cacheKey, profile, createTimespan(0, 0, 15, 0));
  return profile;
}

/**
 * Returns paged results partitioned by status; cache key includes both dimensions.
 *
 * @status string    Filter status.
 * @page numeric     Page number.
 * @return query
 */
public query function getPagedByStatus(required string status, required numeric page) {
  var perPage = 25;
  var offset = (arguments.page - 1) * perPage;
  return queryExecute(
    'SELECT id, email, status FROM users WHERE status = :status ORDER BY id LIMIT :perPage OFFSET :offset',
    {
      status: { value: arguments.status, cfsqltype: 'cf_sql_varchar' },
      perPage: { value: perPage, cfsqltype: 'cf_sql_integer' },
      offset: { value: offset, cfsqltype: 'cf_sql_integer' }
    },
    {
      datasource: variables.datasource,
      cachedWithin: createTimespan(0, 0, 5, 0),
      cacheId: 'paged_users_' & arguments.status & '_' & arguments.page
    }
  );
}
